import React, { useEffect, useState } from "react";
import EventList from "../components/EventList";
import api from "../api";

const BrowseEvents = () => {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [error, setError] = useState(null);

  // Filters state
  const [filters, setFilters] = useState({
    type: "all",          // normal | merchandise | all
    eligibility: "all",   // All Participants | specific | all
    startDate: "",        // YYYY-MM-DD
    endDate: "",          // YYYY-MM-DD
  });

  // Optional: followed clubs IDs
  const [followedClubIds, setFollowedClubIds] = useState([]);

  // Fetch events
  useEffect(() => {
    const fetchEvents = async () => {
      try {
        setLoading(true);
        const token = localStorage.getItem("token");

        // Build query params
        const params = new URLSearchParams();
        if (search) params.append("search", search);
        if (filters.type !== "all") params.append("type", filters.type);
        if (filters.eligibility !== "all") params.append("eligibility", filters.eligibility);
        if (filters.startDate) params.append("startDate", filters.startDate);
        if (filters.endDate) params.append("endDate", filters.endDate);
        if (followedClubIds.length > 0)
          params.append("followedClubs", followedClubIds.join(","));

        const res = await api.get(`/events?${params.toString()}`, {
          headers: { Authorization: `Bearer ${token}` },
        });

        setEvents(res.data);
      } catch (err) {
        console.error("Fetch events error:", err);
        setError("Failed to fetch events");
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, [search, filters, followedClubIds]);

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Browse Events</h1>

      {/* Search */}
      <input
        type="text"
        placeholder="Search events or organisers..."
        className="border p-2 mb-4 w-full"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {/* Filters */}
      <div className="flex gap-4 mb-4 flex-wrap">
        {/* Type Filter */}
        <select
          value={filters.type}
          onChange={(e) => setFilters({ ...filters, type: e.target.value })}
          className="border p-2"
        >
          <option value="all">All Types</option>
          <option value="normal">Normal</option>
          <option value="merchandise">Merchandise</option>
        </select>

        {/* Eligibility Filter */}
        <select
          value={filters.eligibility}
          onChange={(e) =>
            setFilters({ ...filters, eligibility: e.target.value })
          }
          className="border p-2"
        >
          <option value="all">All Participants</option>
          <option value="students">Students</option>
          <option value="faculty">Faculty</option>
        </select>

        {/* Date Range */}
        <input
          type="date"
          value={filters.startDate}
          onChange={(e) =>
            setFilters({ ...filters, startDate: e.target.value })
          }
          className="border p-2"
        />
        <input
          type="date"
          value={filters.endDate}
          onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
          className="border p-2"
        />
      </div>

      {/* Loading/Error */}
      {loading && <p>Loading events...</p>}
      {error && <p className="text-red-500">{error}</p>}

      {/* Event List */}
      {!loading && !error && <EventList events={events} />}
    </div>
  );
};

export default BrowseEvents;
